  const battle = battleOf(state);
  const dangerLanes = new Set(battle.enemies.filter((enemy) => enemy.progress >= .68).map((enemy) => enemy.lane)); const coreThreat = battle.enemies.some((enemy) => enemy.progress >= .84);
