  useEffect(() => { const timer = window.setTimeout(() => { const sourceKey = [SAVE_KEY, ...LEGACY_SAVE_KEYS].find((key) => localStorage.getItem(key)); const raw = sourceKey ? localStorage.getItem(sourceKey) : null; if (raw) { try { const saved = migrateState(JSON.parse(raw)); setState(saved); setStarted(true); setNotice(sourceKey === SAVE_KEY ? "已恢复上次的荣耀记录。" : "旧版存档已安全迁移并恢复。"); } catch { if (sourceKey) localStorage.removeItem(sourceKey); setNotice("存档已损坏，已安全回到新游戏入口。"); } } }, 0); return () => window.clearTimeout(timer); }, []);
