  const saveManually = () => { localStorage.setItem(MANUAL_SAVE_KEY, serializeGameState(state)); setNotice(battle.status === "running" ? "已保存本波开战前状态；再次进入将从准备阶段继续。" : "已写入手动存档。自动存档仍会持续更新。"); };
