function EnemyToken({ enemy, battle, selected, onSelect }: { enemy: Enemy; battle: BattleState; selected: boolean; onSelect: () => void }) { const template = enemyTemplates[enemy.kind]; const effects = battle.effects.filter((effect) => effect.enemyId === enemy.id && ["attack", "hit", "skill", "synergy", "echo"].includes(effect.type)); const latest = effects.at(-1); const point = routePoint(enemy.progress, enemy.lane); const asset = enemyAssets[enemy.kind]; const phase = enemy.kind === "boss" ? DOGMA_COLOSSUS_PHASES.findLast((item) => enemy.bossPhasesTriggered?.includes(item.id)) : enemy.kind === "cave-boss" && enemy.bossPhasesTriggered?.includes(CAVE_SHADOW_PHASE.id) ? CAVE_SHADOW_PHASE : undefined; return <button title={`${template.name}：${template.description}${enemy.blockedBy ? "；当前已被地面单位阻挡" : ""}${phase ? ` 当前阶段 ${phase.name}` : ""}`} className={`enemy-token lane-${enemy.lane} ${template.className} accent-${asset.accent} ${latest ? "hit" : ""} ${enemy.blockedBy ? "blocked" : ""} ${selected ? "selected" : ""}`} onClick={onSelect} style={{ left: `${point.x}%`, top: `${point.y}%` }} aria-label={`查看${template.name}信息${enemy.blockedBy ? "，当前已阻挡" : ""}`}><span>{asset.glyph}</span>{(enemy.kind === "boss" || enemy.kind === "cave-boss") && <strong className="boss-name">{template.name}</strong>}{latest && <em>-{latest.amount}</em>}<i><b style={{ width: `${Math.max(0, enemy.hp / enemy.maxHp) * 100}%` }} /></i></button>; }
function AttackBeam({ slotId, enemy, kind, mode }: { slotId: string; enemy: Enemy; kind: "attack" | "skill"; mode: "melee" | "ranged" }) { const source = deploymentPoint(slotId); const target = routePoint(enemy.progress, enemy.lane); const dx = target.x - source.x; const dy = (target.y - source.y) / MAP_ASPECT_RATIO; const length = Math.hypot(dx, dy); const angle = Math.atan2(dy, dx) * (180 / Math.PI); return <span className={`attack-beam ${kind} ${mode}`} style={{ left: `${source.x}%`, top: `${source.y}%`, width: `${length}%`, transform: `rotate(${angle}deg)` }} />; }
function CombatEffects({ battle }: { battle: BattleState }) { const corePoint = routePoint(1, "upper"); return <div className="combat-effects" aria-hidden="true">{battle.effects.map((effect) => { if (effect.type === "core") return <span key={effect.id} className="effect-core" style={{ left: `${corePoint.x}%`, top: `${corePoint.y}%` }}>-{effect.amount}</span>; if (!effect.slotId || !["heal", "shield", "enemyHit", "debuff", "synergy"].includes(effect.type)) return null; const target = effect.enemyId ? battle.enemies.find((enemy) => enemy.id === effect.enemyId) : undefined; const point = target && effect.type === "debuff" ? routePoint(target.progress, target.lane) : deploymentPoint(effect.slotId); const icon = effect.type === "heal" ? "+" : effect.type === "shield" ? "◈" : effect.type === "debuff" ? "⌁" : effect.type === "enemyHit" ? "!" : "✦"; return <span key={effect.id} className={`effect-pulse ${effect.type}`} style={{ left: `${point.x}%`, top: `${point.y}%` }}>{icon}{effect.amount ? <b>{effect.amount}</b> : null}</span>; })}</div>; }
function SynergyReadout({ state, battle, selected, onSelect }: { state: GameState; battle: BattleState; selected: string | null; onSelect: (id: string | null) => void }) { const deployed = state.pieces.filter((piece) => piece.slotId.startsWith("deploy-")); const greek = deployed.filter((piece) => characterById[piece.characterId].faction === "greece").length; const german = deployed.filter((piece) => characterById[piece.characterId].faction === "germany").length; const dialectic = deployed.filter((piece) => ["socrates", "plato", "hegel"].includes(piece.characterId)).length; const active = [{ id: "greece", visible: greek >= 2, title: `古希腊 ${greek}/4`, short: `对话记录 ${battle.factionCasts.length}/2`, detail: greek >= 4 ? "学院共识：两次古希腊施法也可形成对话；对话后古希腊下次技能强化。" : "理念学园：古希腊与另一阵营各施法后触发对话，全队获得护盾与能量。" }, { id: "germany", visible: german >= 2, title: `德国 ${german}/6`, short: `概念 ${battle.concepts}/${german >= 4 ? 4 : 6}`, detail: german >= 6 ? "绝对体系：本局六名德国角色均施法后触发一次，大量回能并强化技能。" : german >= 4 ? "体系展开：4 层概念触发护盾、回能与一次低倍率回响。" : "体系萌芽：德国角色每次正常施法积累概念，6 层时触发护盾与回能。" }, { id: "dialectic", visible: dialectic >= 2, title: `辩证法 ${dialectic}/3`, short: "矛盾已激活", detail: dialectic >= 3 ? "三人辩证法：三层矛盾爆发并向附近敌人扩散，触发者下次技能强化。" : "两人辩证法：攻击与技能叠加矛盾，三层后范围爆发。" }].filter((item) => item.visible); if (!active.length) return null; return <div className="synergy-readout">{active.map((item) => <button key={item.id} className={selected === item.id ? "active" : ""} onClick={() => onSelect(selected === item.id ? null : item.id)}><b>{item.title}</b><span>{item.short}</span>{selected === item.id && <em>{item.detail}</em>}</button>)}</div>; }
function debugLineup(tokens: string[]): Piece[] { const used = new Set<string>(); return tokens.slice(0, 8).flatMap((token, index) => { const [characterId, requestedStar] = token.split("@"); const unit = characterById[characterId]; if (!unit) return []; const star: Piece["star"] = requestedStar === "3" ? 3 : requestedStar === "2" ? 2 : 1; const slotId = DEPLOY_SLOTS.find((slot) => !used.has(slot) && slotTerrain[slot] === unit.terrain); if (!slotId) return []; used.add(slotId); return [{ id: `debug-${characterId}-${index}`, characterId, star, slotId }]; }); }
function debugFormation(scenario: "merge" | "split" | "max" | "core"): Piece[] { const slots = scenario === "split" ? ["deploy-1", "deploy-3", "deploy-8", "deploy-12", "deploy-13", "deploy-15", "deploy-18", "deploy-20"] : scenario === "core" ? ["deploy-7", "deploy-10", "deploy-11", "deploy-12", "deploy-17", "deploy-18", "deploy-19", "deploy-20"] : ["deploy-5", "deploy-6", "deploy-7", "deploy-10", "deploy-14", "deploy-15", "deploy-17", "deploy-18"]; const groundIds = ["fichte", "heidegger", "hobbes", "epicurus"]; const highlandIds = ["schelling", "kant", "hegel", "bacon"]; let ground = 0; let highland = 0; return slots.map((slotId, index) => { const terrain = slotTerrain[slotId]; const characterId = terrain === "ground" ? groundIds[ground++] : highlandIds[highland++]; return { id: `calibration-${scenario}-${index}`, characterId, star: scenario === "max" ? 3 as const : 1 as const, slotId: slotId as SlotId }; }); }
function FeedbackTools({ state }: { state: GameState }) {
  const [copied, setCopied] = useState(false);
  const report = useMemo(() => JSON.stringify({
    format: "idea-garrison-balance-report-v1",
    generatedAt: new Date().toISOString(),
    demoVersion: "v0.1-demo-rc1",
    progress: { wave: state.wave, level: state.level, xp: state.xp, gold: state.gold, coreHp: state.coreHp, campaignElapsedSeconds: state.campaignElapsedSeconds ?? 0 },
    finalRoster: state.pieces.map((piece) => ({ characterId: piece.characterId, star: piece.star, slotId: piece.slotId })),
    preparationPlan: state.preparationPlan,
    waves: state.balanceHistory ?? [],
  }, null, 2), [state]);
  const download = () => {
    const url = URL.createObjectURL(new Blob([report], { type: "application/json;charset=utf-8" }));
    const link = document.createElement("a");
    link.href = url; link.download = `idea-garrison-balance-${new Date().toISOString().slice(0, 10)}.json`; link.click();
    URL.revokeObjectURL(url);
  };
  const copy = async () => { await navigator.clipboard?.writeText(report); setCopied(true); window.setTimeout(() => setCopied(false), 1200); };
  return <details className="feedback-tools"><summary>反馈工具 <span>FEEDBACK REPORT</span></summary><p>导出本局经济、阵容、路线和战斗统计，便于反馈平衡体验；不包含存档或个人信息。</p><div><button onClick={download}>导出平衡报告</button><button onClick={() => { void copy(); }}>{copied ? "已复制" : "复制报告"}</button></div></details>;
}
function TestControls({ state, locked, onApply, onSpawn, onFormation, onStress, mapDebug, onMapDebug, onReset }: { state: GameState; locked: boolean; onApply: (state: GameState) => void; onSpawn: (wave: 5 | 10, kind: "elite" | "boss") => void; onFormation: (scenario: "merge" | "split" | "max") => void; onStress: () => void; mapDebug: boolean; onMapDebug: (value: boolean) => void; onReset: () => void }) {
  const [gold, setGold] = useState(state.gold); const [level, setLevel] = useState(state.level); const [population, setPopulation] = useState(maxDeployForLevel(state.level)); const [xp, setXp] = useState(state.xp); const [wave, setWave] = useState(state.wave); const [coreHp, setCoreHp] = useState(state.coreHp); const [pendingResearch, setPendingResearch] = useState<number>(state.preparationPlan.pendingResearchChoices ?? 0); const [shopText, setShopText] = useState(state.shop.filter(Boolean).join(",")); const [lineupText, setLineupText] = useState(state.pieces.filter((piece) => isDeploySlot(piece.slotId)).map((piece) => piece.characterId).join(",")); const [saveText, setSaveText] = useState("");
  const apply = () => { const populationLevel = Array.from({ length: MAX_LEVEL }, (_, index) => index + 1).find((candidate) => maxDeployForLevel(candidate) >= Math.min(8, Math.max(2, population))) ?? MAX_LEVEL; const progress = normalizeProgress(Math.max(level, populationLevel), xp); const validShop = shopText.split(",").map((id) => id.trim()).filter((id) => Boolean(characterById[id])).slice(0, 5); const shop: Array<string | null> = [...validShop]; while (shop.length < 5) shop.push(null); const requestedLineup = lineupText.split(",").map((id) => id.trim()).filter(Boolean); onApply({ ...state, gold: Math.max(0, gold), level: progress.level, xp: progress.xp, wave: Math.min(10, Math.max(1, wave)), coreHp: Math.min(100, Math.max(0, coreHp)), shop, pieces: requestedLineup.length ? debugLineup(requestedLineup) : state.pieces, preparationPlan: { ...state.preparationPlan, pendingResearchChoices: Math.max(0, Math.min(2, Math.floor(pendingResearch))) as 0 | 1 | 2, pendingResearchSelections: [] }, battle: undefined }); };
  const exportSave = () => setSaveText(JSON.stringify(JSON.parse(serializeGameState(state)), null, 2));
  const importSave = () => { try { onApply(migrateState(JSON.parse(saveText))); } catch { setSaveText("存档 JSON 无法解析"); } };
  const statistics = { currentWave: { battle: state.battle?.statistics, synergyTriggers: state.battle?.synergyTriggers, bossPhases: state.battle?.bossPhaseLog, summary: state.battle?.summary }, balanceHistory: state.balanceHistory ?? [] };
  return <details className="test-controls developer-tools"><summary>开发平衡工具</summary><p>仅 localhost 且带 <code>?devtools=1</code> 时显示；所有入口默认折叠。</p><div><label>金币<input disabled={locked} type="number" value={gold} onChange={(event) => setGold(Number(event.target.value))} /></label><label>等级<input disabled={locked} type="number" value={level} onChange={(event) => setLevel(Number(event.target.value))} /></label><label>人口<input disabled={locked} type="number" min="2" max="8" value={population} onChange={(event) => setPopulation(Number(event.target.value))} /></label><label>经验<input disabled={locked} type="number" value={xp} onChange={(event) => setXp(Number(event.target.value))} /></label><label>波次<input disabled={locked} type="number" value={wave} onChange={(event) => setWave(Number(event.target.value))} /></label><label>核心<input disabled={locked} type="number" value={coreHp} onChange={(event) => setCoreHp(Number(event.target.value))} /></label><label>英国研究待选<input data-debug="pending-research" disabled={locked} type="number" min="0" max="2" value={pendingResearch} onChange={(event) => setPendingResearch(Number(event.target.value))} /></label></div><label>指定商店（角色 ID，逗号分隔）<input data-debug="shop" disabled={locked} value={shopText} onChange={(event) => setShopText(event.target.value)} /></label><label>指定棋盘阵容（最多 8 人）<textarea data-debug="lineup" disabled={locked} value={lineupText} onChange={(event) => setLineupText(event.target.value)} /></label><div className="developer-actions"><button data-debug="apply" disabled={locked} onClick={apply}>应用开发配置</button><button disabled={locked} onClick={() => onSpawn(5, "elite")}>生成 W5 洞穴之影</button><button disabled={locked} onClick={() => onSpawn(10, "boss")}>生成 W10 绝对精神</button><button data-debug="map-merge" onClick={() => onFormation("merge")}>八人集中汇合区</button><button data-debug="map-split" onClick={() => onFormation("split")}>八人三路分守</button><button data-debug="map-max" onClick={() => onFormation("max")}>最大棋子密集格</button><button data-debug="map-stress" onClick={onStress}>核心前 Boss 压力</button><button data-debug="map-debug" onClick={() => onMapDebug(!mapDebug)}>{mapDebug ? "关闭坐标碰撞框" : "开启坐标碰撞框"}</button><button onClick={exportSave}>导出稳定存档</button><button disabled={locked || !saveText.trim()} onClick={importSave}>导入并迁移存档</button><button disabled={locked} onClick={onReset}>清空存档</button></div><label>存档 JSON<textarea data-debug="save-json" value={saveText} onChange={(event) => setSaveText(event.target.value)} /></label><details><summary>对局平衡报告 JSON</summary><pre>{JSON.stringify(statistics, null, 2)}</pre><button onClick={() => { void navigator.clipboard?.writeText(JSON.stringify(statistics, null, 2)); }}>复制报告</button></details></details>;
}
function FocusReadout({ piece, enemy }: { piece?: Piece; enemy?: Enemy }) { const unit = piece && characterById[piece.characterId]; const target = enemy && enemyTemplates[enemy.kind]; if (unit && piece) return <div className={`focus-readout role-${unit.role.id}`}><span className="focus-icon">{unit.portrait}</span><div><small>{unit.role.label} · {unit.role.cue}</small><strong>{unit.name}　{piece.star}★</strong><em>生命 {Math.ceil(piece.hp ?? unit.stats.resolve)}/{piece.maxHp ?? unit.stats.resolve}　射程 {unit.combat.range}</em></div></div>; if (target && enemy) return <div className={`focus-readout enemy ${target.className}`}><span className="focus-icon">{target.glyph}</span><div><small>敌人情报</small><strong>{target.name}</strong><em>生命 {Math.max(0, Math.ceil(enemy.hp))}/{enemy.maxHp}　核心伤害 {target.coreDamage}</em></div></div>; return null; }
function OperationCue({ status, wave, onBegin, onRetry }: { status: BattleState["status"]; wave: number; onBegin: () => void; onRetry: () => void }) { if (status === "complete") return <div className="operation-cue complete"><small>OPERATION COMPLETE</small><strong>往哲荣耀已成</strong><em>十波侵蚀已被肃清</em></div>; if (status === "defeat") return <div className="operation-cue defeat"><small>CORE BREACHED</small><strong>真理核心失守</strong><button onClick={onRetry}>重整阵线　↻</button></div>; return <div className="operation-cue"><small>{status === "victory" ? "WAVE CLEARED" : "PREPARE FOR DEFENSE"}</small><strong>{status === "victory" ? `第 ${wave} 波待命` : "部署完成后启动防御"}</strong><button onClick={onBegin}>{status === "victory" ? "继续行动　▶" : "启动行动　▶"}</button></div>; }
 function Slot({ slot, piece, selected, hasSelection, locked, dropAllowed, rostrumCandidate = false, buffs, firing, struck, blocking, onDrag, onDrop, onActivate, onSelect, onChooseRostrum, onBlocked }: { slot: SlotId; piece?: Piece; selected: boolean; hasSelection: boolean; locked: boolean; dropAllowed: boolean; rostrumCandidate?: boolean; buffs: string[]; firing: boolean; struck: boolean; blocking: boolean; onDrag: (id: string | null) => void; onDrop: (slot: SlotId) => void; onActivate: (slot: SlotId) => void; onSelect: (id: string) => void; onChooseRostrum?: (id: string) => void; onBlocked: () => void }) { const unit = piece ? characterById[piece.characterId] : undefined; const hpRatio = piece && unit ? Math.max(0, Math.min(1, (piece.hp ?? unit.stats.resolve) / (piece.maxHp ?? unit.stats.resolve))) : 1; const energyRatio = piece && unit ? Math.max(0, Math.min(1, (piece.energy ?? 0) / (piece.maxEnergy ?? unit.combat.maxEnergy))) : 0; const asset = unit ? characterAssets[unit.id] : undefined; const point = isFieldedSlot(slot) ? deploymentPoint(slot) : undefined; const placeStyle = point ? { left: `${point.x}%`, top: `${point.y}%` } : undefined; const throne = isThroneSlot(slot); return <div data-slot={slot} title={throne ? piece && unit ? `哲人王：${unit.name}。最低射程 22，伤害/治疗/护盾 +10%；屏障容量 ${Math.min(4, 1 + unit.block)}。` : "哲人王王座：部署二阶柏拉图后，将一名已部署棋子拖入。" : undefined} style={placeStyle} className={`slot ${throne ? "throne-slot" : ""} ${piece ? "occupied" : ""} ${selected ? "selected" : ""} ${locked ? "locked" : ""} ${dropAllowed ? "drop-allowed" : ""} ${rostrumCandidate ? "rostrum-candidate" : ""} ${firing ? "firing" : ""} ${struck ? "struck" : ""} ${blocking ? "blocking" : ""} ${unit && piece ? `faction-${unit.faction} role-${unit.role.id} terrain-${unit.terrain} accent-${asset?.accent} star-${piece.star}` : ""}`} onClick={() => { if (!piece && !locked) onActivate(slot); }} onDragOver={(event) => event.preventDefault()} onDrop={(event) => { event.preventDefault(); event.stopPropagation(); if (locked) onBlocked(); else onDrop(slot); }}>{piece && unit ? <div data-character-id={unit.id} title={`${unit.name}：${unit.skill.summary}`} className="unit-card" draggable onClick={(event) => { event.stopPropagation(); if (rostrumCandidate && onChooseRostrum) { onChooseRostrum(piece.id); return; } if (hasSelection && !selected) onActivate(slot); else onSelect(piece.id); }} onDragStart={(event) => { if (locked) { event.preventDefault(); onBlocked(); return; } event.dataTransfer?.setData("text/plain", piece.id); if (event.dataTransfer) { event.dataTransfer.effectAllowed = "move"; event.dataTransfer.setDragImage(event.currentTarget, event.currentTarget.offsetWidth / 2, event.currentTarget.offsetHeight / 2); } onDrag(piece.id); }} onDragEnd={() => onDrag(null)}><div className="unit-top"><b>{piece.star} 阶</b><span>{asset?.label ?? unit.role.label}</span></div><div className="unit-avatar">{asset?.glyph ?? unit.portrait}</div>{buffs.length > 0 && <div className="unit-buffs">{buffs.map((buff, index) => <i key={`${buff}-${index}`}>{buff}</i>)}</div>}<div className="unit-name"><strong>{unit.name}</strong></div><div className="unit-gauges"><i className="unit-hp"><b style={{ width: `${hpRatio * 100}%` }} /></i><i className="unit-energy"><b style={{ width: `${energyRatio * 100}%` }} /></i></div></div> : <span className="slot-empty">{throne ? "王座" : slot.startsWith("deploy-") ? "可部署" : slotLabel(slot)}</span>}</div>; }
function rangeStyle(piece: Piece) { const point = deploymentPoint(piece.slotId); const radius = Math.min(48, effectiveAttackRange(piece)); return { left: `${point.x - radius}%`, top: `${point.y - radius * MAP_ASPECT_RATIO}%`, width: `${radius * 2}%`, height: `${radius * 2 * MAP_ASPECT_RATIO}%` }; }
